        if (end === true) {
          expect(results).toEqual([3, 5, 7]);
          done();
          return;
        }
        if (end) {
          done(end);
          return;
        }
        results.push(data);
        collect(null, cb);
      });
    }

    piped(null, function(end: any, data: any) {
      if (end === true) {
        expect(results).toEqual([]);
        done();
        return;
      }
      if (end) {
        done(end);
        return;
